#unet传统
import torch
import torch.nn as nn
import torch.nn.functional as F


class UNetDoubleConv(nn.Module):
    """
    经典 U-Net 的基础卷积块：
    Conv -> ReLU -> Conv -> ReLU
    不加 BatchNorm，不加 Dropout
    """
    def __init__(self, in_channels, out_channels):
        super().__init__()
        self.block = nn.Sequential(
            nn.Conv2d(in_channels, out_channels, kernel_size=3, padding=1, bias=True),
            nn.ReLU(inplace=True),
            nn.Conv2d(out_channels, out_channels, kernel_size=3, padding=1, bias=True),
            nn.ReLU(inplace=True)
        )

    def forward(self, x):
        return self.block(x)


class UNetDown(nn.Module):
    """
    下采样：MaxPool + DoubleConv
    """
    def __init__(self, in_channels, out_channels):
        super().__init__()
        self.block = nn.Sequential(
            nn.MaxPool2d(2),
            UNetDoubleConv(in_channels, out_channels)
        )

    def forward(self, x):
        return self.block(x)


class UNetUp(nn.Module):
    """
    上采样：反卷积 + 拼接 + DoubleConv
    更接近经典 U-Net 的写法
    """
    def __init__(self, in_channels, skip_channels, out_channels):
        super().__init__()
        self.up = nn.ConvTranspose2d(in_channels, in_channels // 2, kernel_size=2, stride=2)
        self.conv = UNetDoubleConv(in_channels // 2 + skip_channels, out_channels)

    def forward(self, x1, x2):
        x1 = self.up(x1)

        # 为了兼容输入尺寸不是严格 2^n 的情况，做一下 padding 对齐
        diff_y = x2.size(2) - x1.size(2)
        diff_x = x2.size(3) - x1.size(3)

        x1 = F.pad(
            x1,
            [diff_x // 2, diff_x - diff_x // 2,
             diff_y // 2, diff_y - diff_y // 2]
        )

        x = torch.cat([x2, x1], dim=1)
        return self.conv(x)


class UNetOutConv(nn.Module):
    """
    最终 1x1 卷积输出分类通道
    """
    def __init__(self, in_channels, num_classes):
        super().__init__()
        self.conv = nn.Conv2d(in_channels, num_classes, kernel_size=1)

    def forward(self, x):
        return self.conv(x)


class UNet_Classic(nn.Module):
    """
    经典传统 U-Net
    已适配你的 train.py 接口：
    model = archs.__dict__[config['arch']](
        num_classes=...,
        input_channels=...,
        deep_supervision=...,
        embed_dims=...
    )

    其中 deep_supervision / embed_dims 会被安全忽略，不会报错。
    """
    def __init__(self, num_classes, input_channels=3, **kwargs):
        super().__init__()

        self.in_conv = UNetDoubleConv(input_channels, 64)
        self.down1 = UNetDown(64, 128)
        self.down2 = UNetDown(128, 256)
        self.down3 = UNetDown(256, 512)
        self.down4 = UNetDown(512, 1024)

        self.up1 = UNetUp(1024, 512, 512)
        self.up2 = UNetUp(512, 256, 256)
        self.up3 = UNetUp(256, 128, 128)
        self.up4 = UNetUp(128, 64, 64)

        self.out_conv = UNetOutConv(64, num_classes)

    def forward(self, x):
        x1 = self.in_conv(x)     # 64
        x2 = self.down1(x1)      # 128
        x3 = self.down2(x2)      # 256
        x4 = self.down3(x3)      # 512
        x5 = self.down4(x4)      # 1024

        x = self.up1(x5, x4)
        x = self.up2(x, x3)
        x = self.up3(x, x2)
        x = self.up4(x, x1)

        logits = self.out_conv(x)
        return logits






